181	/// Mutable wrapper around a [`Pack`] that enforces invariants on every CRUD operation.
182	///
183	/// Macro name uniqueness is enforced within a category, not globally.
184	pub struct PackEditor {
185	    pack: Pack,
186	}
187	
188	impl PackEditor {
189	    pub fn new(pack: Pack) -> Self {
190	        Self { pack }
191	    }
192	
193	    pub fn pack(&self) -> &Pack {
194	        &self.pack
195	    }
196	
197	    pub fn into_pack(self) -> Pack {
198	        self.pack
199	    }
